def load_config(path: str) -> Dict[str, Any]:
    with open(path, "r", encoding="utf-8") as f:
        return json.load(f)


def apply_config(client: KongAdminClient, cfg: Dict[str, Any]) -> Dict[str, Any]:
    results: Dict[str, Any] = {"services": [], "routes": [], "upstreams": [], "targets": []}

    for upstream in cfg.get("upstreams", []) or []:
        upstream_obj = client.upsert_upstream(upstream)
        results["upstreams"].append(upstream_obj)

        upstream_name = upstream["name"]
        targets = upstream.get("targets", []) or []
        if targets:
            created_targets = client.ensure_targets(
                upstream_name,
                targets,
                skip_if_exists=cfg.get("skip_existing_targets", True),
            )
            results["targets"].extend(created_targets)

    for service in cfg.get("services", []) or []:
        service_obj = client.upsert_service(service)
        results["services"].append(service_obj)

    for route in cfg.get("routes", []) or []:
        route_obj = client.upsert_route(route)
        results["routes"].append(route_obj)

    return results


def parse_headers(header_list: List[str]) -> Dict[str, str]:
    out: Dict[str, str] = {}
    for h in header_list:
        if ":" not in h:
            raise ValueError(f"Invalid header format: {h!r}. Expected 'Key: Value'")
        k, v = h.split(":", 1)
        out[k.strip()] = v.strip()
    return out


